#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>

using namespace std;

// Helper function to check if a character is a lowercase letter
inline bool isLetter(char c) {
    return c >= 'a' && c <= 'z';
}

std::vector<long long> solve(std::vector<std::string> chunks, std::vector<std::string> queries) {
    // 1. Concatenate chunks to form s
    std::string s = "";
    for (const auto& chunk : chunks) {
        s += chunk;
    }

    const int N = s.length();
    std::unordered_map<std::string, long long> wordCounts;

    int i = 0;
    while (i < N) {
        char char_i = s[i];

        // Check for separators
        if (!isLetter(char_i)) {
            // If it's not a letter, it's a separator. Skip.
            i++;
            continue;
        }

        // Potential word starts at i (since char_i is a letter)
        int j = i;
        while (j < N) {
            char current_char = s[j];

            if (isLetter(current_char)) {
                // Letters always continue the word
                j++;
            } else if (current_char == '-') {
                // Check hyphen validity: must be surrounded by letters in s

                // s[j-1] must be a letter (guaranteed because j started at i, which was a letter, 
                // and all previous characters up to j-1 must have been part of the word)
                // Check s[j+1]

                bool is_valid_hyphen = isLetter(s[j-1]) && // Redundant check, but safe
                                       (j + 1 < N && isLetter(s[j+1]));

                if (is_valid_hyphen) {
                    j++;
                } else {
                    // Invalid hyphen acts as a separator. Word ends before j.
                    break;
                }
            } else {
                // Non-letter, non-hyphen separator. Word ends before j.
                break;
            }
        }

        // Word found: s.substr(i, j - i)
        // The length is j - i.
        std::string word = s.substr(i, j - i);

        // Record count
        wordCounts[word]++;

        // Move index i to start searching after the current word
        i = j;
    }

    // 3. Process queries
    std::vector<long long> results;
    for (const auto& query : queries) {
        // Since queries[i] is guaranteed to be an effective word, it must have been counted if it exists.
        // We use .count() or [] access carefully. If we use [] it inserts default value 0, which is fine.
        // Using find() is safer if we strictly want to avoid map modification during read phase, 
        // but since we initialized it, using [] is fine for lookup.
        if (wordCounts.count(query)) {
            results.push_back(wordCounts[query]);
        } else {
            results.push_back(0);
        }
    }

    return results;
}
