    std::vector<long long> solve(std::vector<std::string> chunks, std::vector<std::string> queries) {
        // 1. Concatenate chunks
        std::string s = "";
        for (const auto& chunk : chunks) {
            s += chunk;
        }

        const int N = s.length();
        std::unordered_map<std::string, long long> wordCounts;

        auto isLetter = [](char c) {
            return c >= 'a' && c <= 'z';
        };

        int i = 0;
        while (i < N) {
            char char_i = s[i];

            if (!isLetter(char_i)) {
                // If it's not a letter, it's a separator. Skip until the next potential start.
                i++;
                continue;
            }

            // Potential word starts at i
            int j = i;
            while (j < N) {
                char current_char = s[j];

                if (isLetter(current_char)) {
                    // Letters always continue the word
                    j++;
                } else if (current_char == '-') {
                    // Check hyphen validity: must be surrounded by letters in s
                    // s[j-1] is guaranteed to be a letter because we started at a letter i, 
                    // and all characters up to j-1 were either letters or valid hyphens.
                    char prev_char = s[j - 1];

                    // Check if there is a next character AND if it's a letter
                    bool next_char_is_letter = (j + 1 < N) && isLetter(s[j + 1]);

                    // Since we are inside the word boundary established by the starting letter, 
                    // s[j-1] must be a letter (or a hyphen followed by a letter, but the structure 
                    // guarantees the character right before '-' was part of the word sequence). 
                    // If j>0 and we are extending a word, s[j-1] must be either a letter or a valid hyphen.
                    // The logic in the JS reference checks: isLetter(prev_char) && (j + 1 < N && isLetter(next_char)).
                    // Since we only enter this block if j >= i (and i started with a letter), and we only increment j 
                    // if the previous character was accepted, s[j-1] must be a letter if j-1 was the start of a segment or 
                    // if it was a letter itself. 
                    // If s[j-1] was a valid hyphen, it must have been preceded by a letter, and followed by a letter.
                    // Let's stick strictly to the JS logic structure:

                    bool is_valid_hyphen = isLetter(prev_char) && next_char_is_letter;

                    if (is_valid_hyphen) {
                        j++;
                    } else {
                        // Invalid hyphen acts as a separator. Word ends before j.
                        break;
                    }
                } else {
                    // Non-letter, non-hyphen separator. Word ends before j.
                    break;
                }
            }

            // Word found: s.substr(i, j)
            std::string word = s.substr(i, j - i);

            // Record count
            wordCounts[word]++;

            // Move index i to start searching after the current word
            i = j;
        }

        // Process queries
        std::vector<long long> results;
        for (const auto& query : queries) {
            // Since queries are guaranteed to be valid words, they must exist in wordCounts 
